SELECT AVG(volume) AS average_volume
FROM market_data
WHERE ticker_id = 0;

SELECT SUM(volume) AS total_trading_volume
FROM market_data
WHERE ticker_id = 0 AND date BETWEEN '2020-06-01' AND '2020-06-30';

SELECT AVG(total_volume) AS avg_total_volume
FROM (
    SELECT ticker_id, SUM(quantity) AS total_volume
    FROM trades
    GROUP BY ticker_id
);

SELECT DISTINCT se.exchange_code
FROM stock_exchanges se
JOIN tickers t ON se.exchange_id = t.exchange_id
WHERE t.ticker_id IN (
    SELECT ticker_id FROM trades
) AND t.ticker_id IN (
    SELECT ticker_id FROM market_news
);

SELECT ticker_symbol 
FROM tickers 
WHERE ticker_id = 0;

SELECT COUNT(trade_id) 
FROM trades 
WHERE ticker_id = (SELECT ticker_id FROM tickers WHERE ticker_symbol = 'AAPL');
